import sys

class Solution:
    def findCircleNumber(self, isConnected: list[list[int]]) -> int:
        n = len(isConnected)
        visited = [False] * n
        def dfs(city):
            visited[city] = True
            for neighbor, connected in enumerate(isConnected[city]):
                if connected and not visited[neighbor]:
                    dfs(neighbor)

        provinces = 0
        for city in range(n):
            if not visited[city]:
                dfs(city)
                provinces += 1
        return provinces

