#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findCircleNumber(vector<vector<int>>& isConnected) {
        int n = isConnected.size();
        vector<bool> visited(n, false);
        function<void(int)> dfs = [&](int city) {
            visited[city] = true;
            for (int neighbor = 0; neighbor < n; ++neighbor) {
                if (isConnected[city][neighbor] && !visited[neighbor]) {
                    dfs(neighbor);
                }
            }
        };
        int provinces = 0;
        for (int city = 0; city < n; ++city) {
            if (!visited[city]) {
                dfs(city);
                ++provinces;
            }
        }
        return provinces;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<vector<int>> isConnected(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (!(cin >> isConnected[i][j])) return 0;
        }
    }
    Solution sol;
    int ans = sol.findCircleNumber(isConnected);
    cout << ans << "\n";
    return 0;
}
